9385 /// Connect the epilogue vector loop generated for \p EpiPlan to the main vector
9386 // loop, after both plans have executed, updating branches from the iteration
9387 // and runtime checks of the main loop, as well as updating various phis. \p
9388 // InstsToMove contains instructions that need to be moved to the preheader of
9389 // the epilogue vector loop.
9390 static void connectEpilogueVectorLoop(
9391     VPlan &EpiPlan, Loop *L, EpilogueLoopVectorizationInfo &EPI,
9392     DominatorTree *DT, LoopVectorizationLegality &LVL,
9393     DenseMap<const SCEV *, Value *> &ExpandedSCEVs, GeneratedRTChecks &Checks,
9394     ArrayRef<Instruction *> InstsToMove) {
9395   BasicBlock *VecEpilogueIterationCountCheck =
9396       cast<VPIRBasicBlock>(EpiPlan.getEntry())->getIRBasicBlock();
9397 
9398   BasicBlock *VecEpiloguePreHeader =
9399       cast<BranchInst>(VecEpilogueIterationCountCheck->getTerminator())
9400           ->getSuccessor(1);
9401   // Adjust the control flow taking the state info from the main loop
9402   // vectorization into account.
9403   assert(EPI.MainLoopIterationCountCheck && EPI.EpilogueIterationCountCheck &&
9404          "expected this to be saved from the previous pass.");
9405   DomTreeUpdater DTU(DT, DomTreeUpdater::UpdateStrategy::Eager);
9406   EPI.MainLoopIterationCountCheck->getTerminator()->replaceUsesOfWith(
9407       VecEpilogueIterationCountCheck, VecEpiloguePreHeader);
9408 
9409   DTU.applyUpdates({{DominatorTree::Delete, EPI.MainLoopIterationCountCheck,
9410                      VecEpilogueIterationCountCheck},
9411                     {DominatorTree::Insert, EPI.MainLoopIterationCountCheck,
9412                      VecEpiloguePreHeader}});
9413 
9414   BasicBlock *ScalarPH =
9415       cast<VPIRBasicBlock>(EpiPlan.getScalarPreheader())->getIRBasicBlock();
9416   EPI.EpilogueIterationCountCheck->getTerminator()->replaceUsesOfWith(
9417       VecEpilogueIterationCountCheck, ScalarPH);
9418   DTU.applyUpdates(
9419       {{DominatorTree::Delete, EPI.EpilogueIterationCountCheck,
9420         VecEpilogueIterationCountCheck},
9421        {DominatorTree::Insert, EPI.EpilogueIterationCountCheck, ScalarPH}});
9422 
9423   // Adjust the terminators of runtime check blocks and phis using them.
9424   BasicBlock *SCEVCheckBlock = Checks.getSCEVChecks().second;
9425   BasicBlock *MemCheckBlock = Checks.getMemRuntimeChecks().second;
9426   if (SCEVCheckBlock) {
9427     SCEVCheckBlock->getTerminator()->replaceUsesOfWith(
9428         VecEpilogueIterationCountCheck, ScalarPH);
9429     DTU.applyUpdates({{DominatorTree::Delete, SCEVCheckBlock,
9430                        VecEpilogueIterationCountCheck},
9431                       {DominatorTree::Insert, SCEVCheckBlock, ScalarPH}});
9432   }
9433   if (MemCheckBlock) {
9434     MemCheckBlock->getTerminator()->replaceUsesOfWith(
9435         VecEpilogueIterationCountCheck, ScalarPH);
9436     DTU.applyUpdates(
9437         {{DominatorTree::Delete, MemCheckBlock, VecEpilogueIterationCountCheck},
9438          {DominatorTree::Insert, MemCheckBlock, ScalarPH}});
9439   }
9440 
9441   // The vec.epilog.iter.check block may contain Phi nodes from inductions
9442   // or reductions which merge control-flow from the latch block and the
9443   // middle block. Update the incoming values here and move the Phi into the
9444   // preheader.
9445   SmallVector<PHINode *, 4> PhisInBlock(
9446       llvm::make_pointer_range(VecEpilogueIterationCountCheck->phis()));
9447 
9448   for (PHINode *Phi : PhisInBlock) {
9449     Phi->moveBefore(VecEpiloguePreHeader->getFirstNonPHIIt());
9450     Phi->replaceIncomingBlockWith(
9451         VecEpilogueIterationCountCheck->getSinglePredecessor(),
9452         VecEpilogueIterationCountCheck);
9453 
9454     // If the phi doesn't have an incoming value from the
9455     // EpilogueIterationCountCheck, we are done. Otherwise remove the
9456     // incoming value and also those from other check blocks. This is needed
9457     // for reduction phis only.
9458     if (none_of(Phi->blocks(), [&](BasicBlock *IncB) {
9459           return EPI.EpilogueIterationCountCheck == IncB;
9460         }))
9461       continue;
9462     Phi->removeIncomingValue(EPI.EpilogueIterationCountCheck);
9463     if (SCEVCheckBlock)
9464       Phi->removeIncomingValue(SCEVCheckBlock);
9465     if (MemCheckBlock)
9466       Phi->removeIncomingValue(MemCheckBlock);
9467   }
9468 
9469   auto IP = VecEpiloguePreHeader->getFirstNonPHIIt();
9470   for (auto *I : InstsToMove)
9471     I->moveBefore(IP);
9472 
9473   // VecEpilogueIterationCountCheck conditionally skips over the epilogue loop
9474   // after executing the main loop. We need to update the resume values of
9475   // inductions and reductions during epilogue vectorization.
9476   fixScalarResumeValuesFromBypass(VecEpilogueIterationCountCheck, L, EpiPlan,
9477                                   LVL, ExpandedSCEVs, EPI.VectorTripCount);
9478 }
