7395 DenseMap<const SCEV *, Value *> LoopVectorizationPlanner::executePlan(
7396     ElementCount BestVF, unsigned BestUF, VPlan &BestVPlan,
7397     InnerLoopVectorizer &ILV, DominatorTree *DT, bool VectorizingEpilogue) {
7398   assert(BestVPlan.hasVF(BestVF) &&
7399          "Trying to execute plan with unsupported VF");
7400   assert(BestVPlan.hasUF(BestUF) &&
7401          "Trying to execute plan with unsupported UF");
7402   if (BestVPlan.hasEarlyExit())
7403     ++LoopsEarlyExitVectorized;
7404   // TODO: Move to VPlan transform stage once the transition to the VPlan-based
7405   // cost model is complete for better cost estimates.
7406   RUN_VPLAN_PASS(VPlanTransforms::unrollByUF, BestVPlan, BestUF);
7407   RUN_VPLAN_PASS(VPlanTransforms::materializePacksAndUnpacks, BestVPlan);
7408   RUN_VPLAN_PASS(VPlanTransforms::materializeBroadcasts, BestVPlan);
7409   RUN_VPLAN_PASS(VPlanTransforms::replicateByVF, BestVPlan, BestVF);
7410   bool HasBranchWeights =
7411       hasBranchWeightMD(*OrigLoop->getLoopLatch()->getTerminator());
7412   if (HasBranchWeights) {
7413     std::optional<unsigned> VScale = CM.getVScaleForTuning();
7414     RUN_VPLAN_PASS(VPlanTransforms::addBranchWeightToMiddleTerminator,
7415                    BestVPlan, BestVF, VScale);
7416   }
7417 
7418   // Checks are the same for all VPlans, added to BestVPlan only for
7419   // compactness.
7420   attachRuntimeChecks(BestVPlan, ILV.RTChecks, HasBranchWeights);
7421 
7422   // Retrieving VectorPH now when it's easier while VPlan still has Regions.
7423   VPBasicBlock *VectorPH = cast<VPBasicBlock>(BestVPlan.getVectorPreheader());
7424 
7425   VPlanTransforms::optimizeForVFAndUF(BestVPlan, BestVF, BestUF, PSE);
7426   VPlanTransforms::simplifyRecipes(BestVPlan);
7427   VPlanTransforms::removeBranchOnConst(BestVPlan);
7428   if (BestVPlan.getEntry()->getSingleSuccessor() ==
7429       BestVPlan.getScalarPreheader()) {
7430     // TODO: The vector loop would be dead, should not even try to vectorize.
7431     ORE->emit([&]() {
7432       return OptimizationRemarkAnalysis(DEBUG_TYPE, "VectorizationDead",
7433                                         OrigLoop->getStartLoc(),
7434                                         OrigLoop->getHeader())
7435              << "Created vector loop never executes due to insufficient trip "
7436                 "count.";
7437     });
7438     return DenseMap<const SCEV *, Value *>();
7439   }
7440 
7441   VPlanTransforms::narrowInterleaveGroups(
7442       BestVPlan, BestVF,
7443       TTI.getRegisterBitWidth(BestVF.isScalable()
7444                                   ? TargetTransformInfo::RGK_ScalableVector
7445                                   : TargetTransformInfo::RGK_FixedWidthVector));
7446   VPlanTransforms::removeDeadRecipes(BestVPlan);
7447 
7448   VPlanTransforms::convertToConcreteRecipes(BestVPlan);
7449   // Convert the exit condition to AVLNext == 0 for EVL tail folded loops.
7450   VPlanTransforms::convertEVLExitCond(BestVPlan);
7451   // Regions are dissolved after optimizing for VF and UF, which completely
7452   // removes unneeded loop regions first.
7453   VPlanTransforms::dissolveLoopRegions(BestVPlan);
7454   // Expand BranchOnTwoConds after dissolution, when latch has direct access to
7455   // its successors.
7456   VPlanTransforms::expandBranchOnTwoConds(BestVPlan);
7457   // Canonicalize EVL loops after regions are dissolved.
7458   VPlanTransforms::canonicalizeEVLLoops(BestVPlan);
7459   VPlanTransforms::materializeBackedgeTakenCount(BestVPlan, VectorPH);
7460   VPlanTransforms::materializeVectorTripCount(
7461       BestVPlan, VectorPH, CM.foldTailByMasking(),
7462       CM.requiresScalarEpilogue(BestVF.isVector()));
7463   VPlanTransforms::materializeVFAndVFxUF(BestVPlan, VectorPH, BestVF);
7464   VPlanTransforms::cse(BestVPlan);
7465   VPlanTransforms::simplifyRecipes(BestVPlan);
7466 
7467   // 0. Generate SCEV-dependent code in the entry, including TripCount, before
7468   // making any changes to the CFG.
7469   DenseMap<const SCEV *, Value *> ExpandedSCEVs =
7470       VPlanTransforms::expandSCEVs(BestVPlan, *PSE.getSE());
7471   if (!ILV.getTripCount()) {
7472     ILV.setTripCount(BestVPlan.getTripCount()->getLiveInIRValue());
7473   } else {
7474     assert(VectorizingEpilogue && "should only re-use the existing trip "
7475                                   "count during epilogue vectorization");
7476   }
7477 
7478   // Perform the actual loop transformation.
7479   VPTransformState State(&TTI, BestVF, LI, DT, ILV.AC, ILV.Builder, &BestVPlan,
7480                          OrigLoop->getParentLoop(),
7481                          Legal->getWidestInductionType());
7482 
7483 #ifdef EXPENSIVE_CHECKS
7484   assert(DT->verify(DominatorTree::VerificationLevel::Fast));
7485 #endif
7486 
7487   // 1. Set up the skeleton for vectorization, including vector pre-header and
7488   // middle block. The vector loop is created during VPlan execution.
7489   State.CFG.PrevBB = ILV.createVectorizedLoopSkeleton();
7490   replaceVPBBWithIRVPBB(BestVPlan.getScalarPreheader(),
7491                         State.CFG.PrevBB->getSingleSuccessor(), &BestVPlan);
7492   VPlanTransforms::removeDeadRecipes(BestVPlan);
7493 
7494   assert(verifyVPlanIsValid(BestVPlan, true /*VerifyLate*/) &&
7495          "final VPlan is invalid");
7496 
7497   // After vectorization, the exit blocks of the original loop will have
7498   // additional predecessors. Invalidate SCEVs for the exit phis in case SE
7499   // looked through single-entry phis.
7500   ScalarEvolution &SE = *PSE.getSE();
7501   for (VPIRBasicBlock *Exit : BestVPlan.getExitBlocks()) {
7502     if (!Exit->hasPredecessors())
7503       continue;
7504     for (VPRecipeBase &PhiR : Exit->phis())
7505       SE.forgetLcssaPhiWithNewPredecessor(OrigLoop,
7506                                           &cast<VPIRPhi>(PhiR).getIRPhi());
